try {
  const item = $input.first();
  const inputJson = item.json || {};
  const inputBinary = item.binary || {};
  const body = inputJson.body && typeof inputJson.body === 'object' ? inputJson.body : {};
  const sourceTrigger = inputJson.message || inputJson.callback_query ? 'telegram' : (inputJson.headers || inputJson.query || inputJson.params ? 'webhook' : 'form');
  const binaryCandidates = ['invoice_file', 'data', 'file', 'attachment'];
  let binaryKey = binaryCandidates.find((key) => inputBinary[key]) || Object.keys(inputBinary)[0];
  const outputBinary = {};
  let meta = {};

  if (binaryKey && inputBinary[binaryKey]) {
    meta = inputBinary[binaryKey];
    outputBinary.data = inputBinary[binaryKey];
    binaryKey = 'data';
  }

  const base64Value = body.file_base64 || inputJson.file_base64;
  if (!binaryKey && base64Value) {
    const cleanBase64 = String(base64Value).replace(/^data:[^;]+;base64,/, '');
    const mimeType = body.mime_type || inputJson.mime_type || 'application/pdf';
    const fileName = body.file_name || inputJson.file_name || 'invoice-upload';
    outputBinary.data = {
      data: cleanBase64,
      mimeType,
      fileName,
    };
    meta = outputBinary.data;
    binaryKey = 'data';
  }

  const mimeType = meta.mimeType || body.mime_type || inputJson.mime_type || '';
  const fileName = meta.fileName || body.file_name || inputJson.file_name || 'invoice-upload';
  const allowedMimeTypes = ['application/pdf', 'image/png', 'image/jpeg', 'image/jpg', 'image/webp', 'image/gif'];
  const allowedExtensions = /\.(pdf|png|jpe?g|webp|gif)$/i;
  const isAllowed = allowedMimeTypes.includes(String(mimeType).toLowerCase()) || allowedExtensions.test(fileName);
  const errors = [];

  if (!binaryKey) errors.push('Missing invoice_file binary upload or file_base64 payload.');
  if (binaryKey && !isAllowed) errors.push(`Unsupported file type: ${mimeType || fileName || 'unknown'}.`);

  return [{
    json: {
      source_trigger: sourceTrigger,
      source_filename: fileName,
      mime_type: mimeType,
      openai_content_type: String(mimeType).toLowerCase() === 'application/pdf' || /\.pdf$/i.test(fileName) ? 'input_file' : 'input_image',
      is_processable: errors.length === 0,
      validation_errors: errors.join('; '),
    },
    binary: outputBinary,
  }];
} catch (error) {
  return [{
    json: {
      source_trigger: 'unknown',
      source_filename: 'unknown_file',
      mime_type: '',
      is_processable: false,
      validation_errors: `Prepare input failed: ${error.message}`,
    },
  }];
}

try {
  const item = $input.first();
  const data = item.json || {};

  const errors = Array.isArray(data.validation_errors)
    ? data.validation_errors.join(', ')
    : data.validation_errors || 'Unsupported or missing invoice file.';

  const fileName = data.source_filename || 'unknown_file';
  const trigger = data.source_trigger || 'unknown_trigger';

  return [{
    json: {
      status: 'error',
      source_trigger: trigger,
      source_filename: fileName,
      invoice_number: data.invoice_number || null,
      validation_status: 'rejected',
      validation_errors: errors,
      sheet_append_result: null,
      telegram_message: `❌ Invoice OCR Rejected\n\n📄 File:\n${fileName}\n\n⚠️ Reason:\n${errors}\n\n🧾 Invoice Number:\n${data.invoice_number || 'N/A'}\n\n🔄 Trigger:\n${trigger}`,
      log: {
        timestamp: new Date().toISOString(),
        stage: 'validation',
        success: false,
      },
    },
  }];
} catch (error) {
  return [{
    json: {
      status: 'error',
      validation_status: 'rejected',
      validation_errors: `Build invalid result failed: ${error.message}`,
      telegram_message: `❌ Invoice OCR Rejected\n\n⚠️ Reason:\n${error.message}`,
    },
  }];
}

try {
  const items = $input.all();

  function parseJson(value) {
    if (typeof value !== 'string') return value;

    try {
      return JSON.parse(
        value
          .replace(/```json/g, '')
          .replace(/```/g, '')
          .trim()
      );
    } catch {
      return null;
    }
  }

  function looksNumeric(text) {
    if (!text) return false;
    const cleaned = text.replace(/,/g, '');
    return cleaned !== '' && !Number.isNaN(Number(cleaned));
  }

  function cleanValue(value) {
    if (value === undefined || value === '') return null;

    if (typeof value === 'string') {
      const text = value.trim();

      if (looksNumeric(text)) {
        const num = Number(text.replace(/,/g, ''));
        if (!isNaN(num)) return num;
      }

      const date = new Date(text);
      if (!isNaN(date.getTime()) && /\d{4}|\d{2}/.test(text)) {
        return date.toISOString().split('T')[0];
      }

      return text;
    }

    if (Array.isArray(value)) return value.map(cleanValue);

    if (typeof value === 'object' && value !== null) {
      const cleaned = {};
      for (const key in value) cleaned[key] = cleanValue(value[key]);
      return cleaned;
    }

    return value;
  }

  return items.map((item) => {
    let raw = item.json?.content?.parts?.[0]?.text || item.json?.text || item.json;
    raw = parseJson(raw);

    if (!raw) {
      return {
        json: {
          is_valid: false,
          error: 'Cannot parse JSON',
          data: { line_items: [] },
        },
      };
    }

    const cleanedData = cleanValue(raw);
    if (!Array.isArray(cleanedData.line_items)) cleanedData.line_items = [];

    return {
      json: {
        is_valid: true,
        data: cleanedData,
      },
    };
  });
} catch (error) {
  return [{
    json: {
      is_valid: false,
      error: `Normalize and validate failed: ${error.message}`,
      data: { line_items: [] },
    },
  }];
}

try {
  const items = $('Split Out').all();
  const first = items[0]?.json || {};
  const rootData = {};

  for (const key in first) {
    if (key === 'data_line_items' || key === 'line_items') continue;
    rootData[key] = first[key];
  }

  function getLineItem(item) {
    return item.json.data_line_items || item.json.line_items || item.json.item || {};
  }

  function htmlEscape(value) {
    return String(value ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  const infoHtml = Object.entries(rootData)
    .map(([key, value]) => {
      if (value === null || value === undefined || typeof value === 'object') return '';
      return `
        <tr>
          <td style="padding:8px;border:1px solid #ddd;font-weight:bold;background:#f8fafc;">${htmlEscape(key)}</td>
          <td style="padding:8px;border:1px solid #ddd;">${htmlEscape(value)}</td>
        </tr>`;
    })
    .join('');

  const sampleLine = getLineItem(items[0]);
  const columns = Object.keys(sampleLine);
  const tableHeader = columns
    .map((col) => `<th style="padding:8px;border:1px solid #ddd;background:#f1f5f9;">${htmlEscape(col)}</th>`)
    .join('');

  const tableRows = items
    .map((item) => {
      const line = getLineItem(item);
      return `<tr>${columns.map((col) => `<td style="padding:8px;border:1px solid #ddd;">${htmlEscape(line[col] ?? '')}</td>`).join('')}</tr>`;
    })
    .join('');

  const html = `
<div style="font-family: Arial;padding: 20px;background: #f8fafc;border-radius: 12px;border: 1px solid #e2e8f0;">
  <h2 style="margin-top:0;color:#16a34a;">✅ OCR Processing Completed</h2>
  <h3>Invoice Information</h3>
  <table style="width:100%;border-collapse:collapse;background:white;margin-bottom:20px;">${infoHtml}</table>
  <h3>Line Items (${items.length})</h3>
  <table style="width:100%;border-collapse:collapse;background:white;">
    <thead><tr>${tableHeader}</tr></thead>
    <tbody>${tableRows}</tbody>
  </table>
</div>`;

  return [{
    json: {
      status: 'success',
      total_items: items.length,
      html,
      telegram_message: `✅ OCR Processing Completed\n\n📦 Total Line Items: ${items.length}`,
      data: rootData,
    },
  }];
} catch (error) {
  return [{
    json: {
      status: 'error',
      total_items: 0,
      html: '',
      telegram_message: `⚠️ OCR completed, but summary build failed: ${error.message}`,
      data: {},
    },
  }];
}
